#[test]
fn test_llm_has_error_prefix_constant_used_in_decode() {
    // Round-trip: ABI-encode an LLM response with has_error=true and a
    // non-empty error string, then verify decode_llm_response returns an
    // Err that starts with the LLM_HAS_ERROR_PREFIX constant.
    // ABI layout (5-field non-encrypted):
    //   (bool has_error, bytes completion, bytes encrypted, bytes metadata, string error_msg)
    let error_msg = b"test error from executor";
    let mut data = vec![0u8; 10 * 32];
    data[31] = 1; // has_error = true
    data[63] = 0xA0; // offset 160 → completion_data
    data[95] = 0xC0; // offset 192 → encrypted_completion_data
    data[127] = 0xE0; // offset 224 → model_metadata
    data[158] = 0x01; // offset 256 (0x100) → error_message
    data[287] = error_msg.len() as u8;
    data[288..288 + error_msg.len()].copy_from_slice(error_msg);

    let result = decode_llm_response(&Bytes::from(data), false);
    assert!(result.is_err(), "has_error=true must produce Err");

    }
}

