        Token::String(url.to_string()),
        Token::Uint(EthU256::from(1u8)), // GET method
        Token::Array(vec![]),            // headers_keys
        Token::Array(vec![]),            // headers_values
        Token::String(String::new()),    // body
    ];
    Bytes::from(ethabi::encode(&tokens))
}

