proptest! {
    /// Two-phase deadline validation with offset semantics: valid iff offset > ttl
    /// Contract is single source of truth for absolute deadline computation
    #[test]
    fn fuzz_validate_two_phase_deadline_property(
        offset in 0u64..200,
        ttl in 0u64..100
    ) {
        // With offset semantics, we only check offset > ttl
        let expected_valid = offset > ttl;
        let actual_valid = validate_two_phase_deadline(offset, ttl).is_ok();

        assert_eq!(expected_valid, actual_valid,
            "offset={}, ttl={}",
            offset, ttl);
    }

    /// TTL validation: valid iff 0 < ttl <= MAX_TTL_BLOCKS
    #[test]
    fn fuzz_ttl_bounds(ttl in 0u64..200) {
        // Verify TTL bounds logic
        let expected_valid = ttl > 0 && ttl <= MAX_TTL_BLOCKS;

        }

        /// TTL validation: valid iff 0 < ttl <= MAX_TTL_BLOCKS
        #[test]
        fn fuzz_ttl_bounds(ttl in 0u64..200) {
            // Verify TTL bounds logic
            let expected_valid = ttl > 0 && ttl <= MAX_TTL_BLOCKS;

            // The TTL check is part of the overall validation
            // We verify the property holds
            assert!(MAX_TTL_BLOCKS > 0);

            if expected_valid {
                assert!(ttl <= MAX_TTL_BLOCKS && ttl > 0);
            } else {
                assert!(ttl == 0 || ttl > MAX_TTL_BLOCKS);
            }
        }
    }
}

