/// Test: Empty selector set handling
/// Note: Empty set is mathematically a subset of all sets,
/// so it matches the first level (priority 0).
#[test]
fn test_empty_selectors() {
    use alloy_primitives::FixedBytes;
    use ritual_sequencing_rights::{PriorityComputer, SelectorSet, SequencingOrdering};

    let ordering = SequencingOrdering::new(vec![{
        let mut set = SelectorSet::new();
        set.insert(FixedBytes::from_slice(&[0x11, 0x22, 0x33, 0x44]));
        set
    }]);

    let computer = PriorityComputer::new();
    let empty = SelectorSet::new();

    // Empty set is subset of first level, so gets priority 0
    let priority = computer.compute(&empty, &ordering);
    assert_eq!(priority.value(), 0);
}

}

