#[test]
fn test_error_class_system_vs_block_local() {
    use crate::error::{BlockVerificationError, ErrorClass};

    // System-level errors (not block's fault)
    let state_err = BlockVerificationError::StateProviderUnavailable {
        reason: "database down".to_string(),
    };
    assert_eq!(state_err.error_class(), ErrorClass::System);
