#[test]
fn test_filter_result_should_remove_from_pool() {
    // Verify the should_remove_from_pool logic
    assert!(!FilterResult::Valid.should_remove_from_pool());

    // Permanent failures - should remove
    assert!(FilterResult::C1CallNotFound.should_remove_from_pool());
    assert!(FilterResult::C2InvalidState.should_remove_from_pool());
    assert!(FilterResult::C3IndexOutOfBounds.should_remove_from_pool());
    assert!(FilterResult::C5TooLate.should_remove_from_pool());
    assert!(FilterResult::C6Expired.should_remove_from_pool());
    assert!(FilterResult::C7InvalidSignature.should_remove_from_pool());
    assert!(FilterResult::C8InvalidTarget.should_remove_from_pool());
    assert!(FilterResult::C10AlreadyExecuted.should_remove_from_pool());

    // Temporary failures - should NOT remove
    assert!(!FilterResult::C4TooEarly.should_remove_from_pool());
    assert!(!FilterResult::C9InsufficientFunds.should_remove_from_pool());
    assert!(!FilterResult::C10InBlockDuplicate.should_remove_from_pool());

    assert!(!FilterResult::DatabaseError.should_remove_from_pool());
}

