    assert_eq!(calldata.len(), 100);

    // Check caller is properly encoded (address at bytes 4-36, right-aligned in 32 bytes)
    let caller_bytes = &calldata[4..36];
    assert_eq!(&caller_bytes[0..12], &[0u8; 12]); // Left-padded zeros
    assert_eq!(&caller_bytes[12..32], caller.as_slice());

    assert_eq!(U256::from_be_slice(index_bytes), U256::from(5u64));
}

