/// Test call depth tracking
#[test]
fn test_call_depth_tracking() {
    let mut inspector = ContractCallInspector::new();

    // Simulate nested calls
    assert_eq!(inspector.depth, 0);

    inspector.depth += 1; // call() increments
    assert_eq!(inspector.depth, 1);

    inspector.depth += 1; // nested call
    assert_eq!(inspector.depth, 2);

    inspector.depth -= 1; // call_end decrements
    assert_eq!(inspector.depth, 1);

    inspector.depth -= 1;
    assert_eq!(inspector.depth, 0);
}

}

