fn create_http_request_payload(executor: Address, ttl: u64, url: &str) -> Bytes {
    let tokens = vec![
        Token::Address(EthAddress::from_slice(executor.as_slice())),
        Token::Array(vec![]), // encrypted_secrets
        Token::Uint(EthU256::from(ttl)),
        Token::Array(vec![]), // secret_signature
        Token::Bytes(vec![]), // user_public_key
        Token::String(url.to_string()),
        Token::Uint(EthU256::from(1u8)), // GET method
        Token::Array(vec![]),            // headers_keys
        Token::Array(vec![]),            // headers_values
        Token::String(String::new()),    // body
    ];
    Bytes::from(ethabi::encode(&tokens))
}

