/// Test that TTL calculation handles large values safely
#[test]
fn test_ttl_overflow_protection() {
    // In practice, commit_block + ttl should never overflow u64
    // But if it does, Rust's default behavior is panic in debug, wrap in release
    //
    // Maximum realistic values:
    // - commit_block: ~10^9 (Ethereum at ~15s blocks would take ~475 years)
    // - ttl: ~10^6 (a few weeks worth of blocks)
    //
    // Sum: ~10^9 << u64::MAX (~1.8 × 10^19)

    let commit_block: u64 = 1_000_000_000;
    let ttl: u64 = 1_000_000;

